import anthropic
import json

client = anthropic.Anthropic()

def extract_chart_data_with_confidence(image_base64: str, media_type: str = "image/png") -> dict:
    """
    Extract chart data with explicit confidence reporting.
    Low-confidence fields are flagged for human review.
    """
    prompt = """Analyze this chart and extract the data it contains.

For each piece of information you extract, indicate your confidence:
- HIGH: clearly visible, unambiguous
- MEDIUM: readable but could have minor errors
- LOW: small, blurry, partially occluded, or ambiguous

Return a JSON object with this exact structure:
{
  "chart_type": {"value": string, "confidence": "HIGH"|"MEDIUM"|"LOW"},
  "title": {"value": string or null, "confidence": "HIGH"|"MEDIUM"|"LOW"},
  "x_axis_label": {"value": string or null, "confidence": "HIGH"|"MEDIUM"|"LOW"},
  "y_axis_label": {"value": string or null, "confidence": "HIGH"|"MEDIUM"|"LOW"},
  "data_series": [
    {
      "name": {"value": string, "confidence": "HIGH"|"MEDIUM"|"LOW"},
      "values": {"value": [number, ...], "confidence": "HIGH"|"MEDIUM"|"LOW"}
    }
  ],
  "notes": string  // Any observations about quality issues or limitations
}

Return ONLY the JSON object, no markdown fences."""

    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=1500,
        messages=[{
            "role": "user",
            "content": [
                {
                    "type": "image",
                    "source": {"type": "base64", "media_type": media_type, "data": image_base64}
                },
                {"type": "text", "text": prompt}
            ]
        }]
    )

    data = json.loads(response.content[0].text)

    # Flag low-confidence fields for review
    low_confidence_fields = [
        key for key, val in data.items()
        if isinstance(val, dict) and val.get("confidence") == "LOW"
    ]

    if low_confidence_fields:
        print(f"WARNING: Low confidence on fields: {low_confidence_fields}")
        print("Consider human review or image enhancement before using this data.")

    return data
